import React, { useEffect, useRef } from "react";
import * as THREE from "three";
import "./HeroPlayground.css";

/* ==========================================================
   CODE COSMOS — three.js playground filling the hero.
   • Parallax starfield that leans with the cursor
   • Floating neon crystals — click to shatter (+⚡ score)
   • Comets streak across on their own (fun to just watch)
   Renders only while the hero is on screen.
   ========================================================== */

const CRYSTAL_COLORS = [0x4ad8ff, 0x8a6bff, 0xff7f50, 0x4ad8ff, 0x8a6bff, 0xff7f50, 0xffc107];
const CRYSTAL_COUNT = 7;

export default function HeroPlayground({ theme }) {
  const rootRef = useRef(null);
  const mountRef = useRef(null);
  const scoreRef = useRef(null);
  const scoreCount = useRef(0);

  useEffect(() => {
    const root = rootRef.current;
    const mount = mountRef.current;
    if (!root || !mount) return;

    const reduced = window.matchMedia("(prefers-reduced-motion: reduce)").matches;
    const isDark = theme?.name !== "light";
    const accentInt = parseInt((theme?.accentColor || "#FFC107").slice(1), 16);

    let W = mount.clientWidth || 1;
    let H = mount.clientHeight || 1;

    const renderer = new THREE.WebGLRenderer({ alpha: true, antialias: true });
    renderer.setPixelRatio(Math.min(window.devicePixelRatio, 2));
    renderer.setSize(W, H);
    mount.appendChild(renderer.domElement);

    const scene = new THREE.Scene();
    const camera = new THREE.PerspectiveCamera(60, W / H, 0.1, 500);
    camera.position.z = 70;

    const disposables = [];

    /* ---------- soft round sprite for points ---------- */
    function makeGlowSprite() {
      const c = document.createElement("canvas");
      c.width = c.height = 64;
      const ctx = c.getContext("2d");
      const g = ctx.createRadialGradient(32, 32, 0, 32, 32, 32);
      g.addColorStop(0, "rgba(255,255,255,1)");
      g.addColorStop(0.35, "rgba(255,255,255,0.65)");
      g.addColorStop(1, "rgba(255,255,255,0)");
      ctx.fillStyle = g;
      ctx.fillRect(0, 0, 64, 64);
      const tex = new THREE.CanvasTexture(c);
      disposables.push(tex);
      return tex;
    }
    const glowSprite = makeGlowSprite();

    /* ---------- floating crystals ---------- */
    const crystals = [];
    const crystalGeo = new THREE.IcosahedronGeometry(3.0, 0);
    disposables.push(crystalGeo);

    function randomCrystalPos(v) {
      // explicit empty zones so gems never hide behind text or the robot:
      // A far-right column, B top band, C gap between text and robot
      const r = Math.random();
      if (r < 0.55) {
        v.set(48 + Math.random() * 18, -28 + Math.random() * 56, Math.random() * 18);
      } else if (r < 0.85) {
        v.set(-15 + Math.random() * 58, 26 + Math.random() * 10, Math.random() * 16);
      } else {
        v.set(-2 + Math.random() * 18, -34 + Math.random() * 10, Math.random() * 16);
      }
      return v;
    }

    for (let i = 0; i < CRYSTAL_COUNT; i++) {
      const color = CRYSTAL_COLORS[i % CRYSTAL_COLORS.length];
      const wire = new THREE.MeshBasicMaterial({
        color,
        wireframe: true,
        transparent: true,
        opacity: 1,
      });
      const fill = new THREE.MeshBasicMaterial({
        color,
        transparent: true,
        opacity: 0.18,
        depthWrite: false,
      });
      disposables.push(wire, fill);

      const group = new THREE.Group();
      group.add(new THREE.Mesh(crystalGeo, wire));
      group.add(new THREE.Mesh(crystalGeo, fill));
      // soft glowing heart so the gem reads as alive & clickable
      const glowMat = new THREE.SpriteMaterial({
        map: glowSprite,
        color,
        transparent: true,
        opacity: 0.55,
        depthWrite: false,
        blending: THREE.AdditiveBlending,
      });
      const glow = new THREE.Sprite(glowMat);
      glow.scale.setScalar(6);
      group.add(glow);
      disposables.push(glowMat);
      randomCrystalPos(group.position);
      group.userData = {
        baseY: group.position.y,
        phase: Math.random() * Math.PI * 2,
        floatAmp: 2 + Math.random() * 2.5,
        rotX: 0.15 + Math.random() * 0.3,
        rotY: 0.2 + Math.random() * 0.4,
        alive: true,
        respawnAt: 0,
        color,
      };
      scene.add(group);
      crystals.push(group);
    }

    /* ---------- shatter bursts ---------- */
    const bursts = [];
    function shatter(crystal) {
      const n = 46;
      const geo = new THREE.BufferGeometry();
      const pos = new Float32Array(n * 3);
      const vel = new Float32Array(n * 3);
      for (let i = 0; i < n; i++) {
        pos[i * 3] = crystal.position.x;
        pos[i * 3 + 1] = crystal.position.y;
        pos[i * 3 + 2] = crystal.position.z;
        const t = Math.random() * Math.PI * 2;
        const p = Math.acos(2 * Math.random() - 1);
        const s = 14 + Math.random() * 22;
        vel[i * 3] = Math.sin(p) * Math.cos(t) * s;
        vel[i * 3 + 1] = Math.sin(p) * Math.sin(t) * s;
        vel[i * 3 + 2] = Math.cos(p) * s * 0.6;
      }
      geo.setAttribute("position", new THREE.BufferAttribute(pos, 3));
      const mat = new THREE.PointsMaterial({
        size: 1.8,
        color: crystal.userData.color,
        map: glowSprite,
        transparent: true,
        opacity: 1,
        depthWrite: false,
        blending: THREE.AdditiveBlending,
      });
      const pts = new THREE.Points(geo, mat);
      pts.userData = { vel, life: 0 };
      scene.add(pts);
      bursts.push(pts);

      crystal.visible = false;
      crystal.userData.alive = false;
      crystal.userData.respawnAt = clock.elapsedTime + 2.5;
    }

    /* ---------- comets ---------- */
    const comets = [];
    const TRAIL = 22;
    function spawnComet() {
      const geo = new THREE.BufferGeometry();
      geo.setAttribute(
        "position",
        new THREE.BufferAttribute(new Float32Array(TRAIL * 3), 3)
      );
      const mat = new THREE.LineBasicMaterial({
        color: accentInt,
        transparent: true,
        opacity: 0.9,
        depthWrite: false,
      });
      const line = new THREE.Line(geo, mat);
      const fromLeft = Math.random() > 0.5;
      const y0 = (Math.random() - 0.35) * 60;
      line.userData = {
        head: new THREE.Vector3(fromLeft ? -110 : 110, y0, -5 + Math.random() * 20),
        vel: new THREE.Vector3(
          (fromLeft ? 1 : -1) * (90 + Math.random() * 50),
          -14 + Math.random() * 28,
          0
        ),
        life: 0,
        maxLife: 2.4,
      };
      const p = line.geometry.attributes.position.array;
      for (let i = 0; i < TRAIL; i++) {
        p[i * 3] = line.userData.head.x;
        p[i * 3 + 1] = line.userData.head.y;
        p[i * 3 + 2] = line.userData.head.z;
      }
      scene.add(line);
      comets.push(line);
    }
    let nextComet = 1.6 + Math.random() * 2;

    /* ---------- interaction ---------- */
    const mouse = { x: 0, y: 0 };
    const raycaster = new THREE.Raycaster();
    const ndc = new THREE.Vector2();

    function onPointerMove(e) {
      const r = mount.getBoundingClientRect();
      if (r.height === 0) return;
      mouse.x = ((e.clientX - r.left) / r.width - 0.5) * 2;
      mouse.y = ((e.clientY - r.top) / r.height - 0.5) * 2;
    }

    function onClick(e) {
      const r = mount.getBoundingClientRect();
      if (
        e.clientX < r.left ||
        e.clientX > r.right ||
        e.clientY < r.top ||
        e.clientY > r.bottom
      )
        return;
      ndc.set(
        ((e.clientX - r.left) / r.width) * 2 - 1,
        -((e.clientY - r.top) / r.height) * 2 + 1
      );
      raycaster.setFromCamera(ndc, camera);
      const alive = crystals.filter((c) => c.userData.alive);
      const hit = raycaster.intersectObjects(alive, true)[0];
      if (!hit) return;
      const crystal = hit.object.parent;
      shatter(crystal);

      // score pill + floating toast
      scoreCount.current += 1;
      const pill = scoreRef.current;
      if (pill) {
        pill.style.display = "flex";
        pill.textContent = `⚡ ${scoreCount.current}`;
        pill.classList.remove("hp-score-pop");
        void pill.offsetWidth;
        pill.classList.add("hp-score-pop");
      }
      const toast = document.createElement("span");
      toast.className = "hp-toast";
      toast.textContent = "+⚡";
      toast.style.left = `${e.clientX - r.left}px`;
      toast.style.top = `${e.clientY - r.top}px`;
      root.appendChild(toast);
      setTimeout(() => toast.remove(), 900);
    }

    window.addEventListener("pointermove", onPointerMove, { passive: true });
    document.addEventListener("click", onClick);

    /* ---------- resize / visibility ---------- */
    let visible = true;
    const io = new IntersectionObserver(
      ([entry]) => {
        visible = entry.isIntersecting;
      },
      { threshold: 0 }
    );
    io.observe(mount);

    const ro = new ResizeObserver(() => {
      W = mount.clientWidth || 1;
      H = mount.clientHeight || 1;
      renderer.setSize(W, H);
      camera.aspect = W / H;
      camera.updateProjectionMatrix();
    });
    ro.observe(mount);

    /* ---------- render loop ---------- */
    const clock = new THREE.Clock();
    let rafId = null;

    function frame() {
      rafId = requestAnimationFrame(frame);
      if (!visible || document.hidden) return;
      const dt = Math.min(clock.getDelta(), 0.05);
      const t = clock.elapsedTime;

      // cursor parallax
      camera.position.x += (mouse.x * 6 - camera.position.x) * 0.04;
      camera.position.y += (-mouse.y * 4 - camera.position.y) * 0.04;
      camera.lookAt(0, 0, 0);

      // crystals float / respawn
      for (const c of crystals) {
        const u = c.userData;
        if (u.alive) {
          c.position.y = u.baseY + Math.sin(t * 0.6 + u.phase) * u.floatAmp;
          c.rotation.x += u.rotX * dt;
          c.rotation.y += u.rotY * dt;
          const glow = c.children[2];
          if (glow) glow.material.opacity = 0.42 + Math.sin(t * 1.5 + u.phase) * 0.2;
          if (c.scale.x < 1) {
            const s = Math.min(1, c.scale.x + dt * 1.6);
            c.scale.setScalar(s);
          }
        } else if (u.respawnAt && t > u.respawnAt) {
          randomCrystalPos(c.position);
          u.baseY = c.position.y;
          c.scale.setScalar(0.01);
          c.visible = true;
          u.alive = true;
          u.respawnAt = 0;
        }
      }

      // bursts
      for (let i = bursts.length - 1; i >= 0; i--) {
        const b = bursts[i];
        b.userData.life += dt;
        const pos = b.geometry.attributes.position.array;
        const vel = b.userData.vel;
        for (let j = 0; j < vel.length; j++) {
          vel[j] *= 0.965;
          pos[j] += vel[j] * dt;
        }
        b.geometry.attributes.position.needsUpdate = true;
        b.material.opacity = Math.max(0, 1 - b.userData.life / 0.9);
        if (b.userData.life > 0.9) {
          scene.remove(b);
          b.geometry.dispose();
          b.material.dispose();
          bursts.splice(i, 1);
        }
      }

      // comets
      if (!reduced) {
        nextComet -= dt;
        if (nextComet <= 0 && comets.length < 3) {
          spawnComet();
          nextComet = 3 + Math.random() * 4;
        }
      }
      for (let i = comets.length - 1; i >= 0; i--) {
        const cm = comets[i];
        const u = cm.userData;
        u.life += dt;
        u.head.addScaledVector(u.vel, dt);
        const p = cm.geometry.attributes.position.array;
        // shift trail back, head at index 0
        for (let j = TRAIL - 1; j > 0; j--) {
          p[j * 3] = p[(j - 1) * 3];
          p[j * 3 + 1] = p[(j - 1) * 3 + 1];
          p[j * 3 + 2] = p[(j - 1) * 3 + 2];
        }
        p[0] = u.head.x;
        p[1] = u.head.y;
        p[2] = u.head.z;
        cm.geometry.attributes.position.needsUpdate = true;
        cm.material.opacity = Math.max(0, 0.9 * (1 - u.life / u.maxLife));
        if (u.life > u.maxLife) {
          scene.remove(cm);
          cm.geometry.dispose();
          cm.material.dispose();
          comets.splice(i, 1);
        }
      }

      renderer.render(scene, camera);
    }

    if (reduced) {
      // static frame only
      renderer.render(scene, camera);
    } else {
      frame();
    }

    /* ---------- cleanup ---------- */
    return () => {
      if (rafId) cancelAnimationFrame(rafId);
      io.disconnect();
      ro.disconnect();
      window.removeEventListener("pointermove", onPointerMove);
      document.removeEventListener("click", onClick);
      [...bursts, ...comets].forEach((o) => {
        scene.remove(o);
        o.geometry.dispose();
        o.material.dispose();
      });
      disposables.forEach((d) => d.dispose());
      renderer.dispose();
      if (renderer.domElement.parentElement === mount)
        mount.removeChild(renderer.domElement);
    };
  }, [theme?.name, theme?.accentColor]);

  return (
    <div ref={rootRef} className="hero-playground" aria-hidden="true">
      <div ref={mountRef} className="hero-playground-canvas" />
      <div ref={scoreRef} className="hp-score" style={{ display: "none" }} />
    </div>
  );
}
